+    // ── Test scaffolding types ──────────────────────────────────────────
+
+    #[derive(Clone, Copy, Debug, PartialEq, Eq, Serialize, Deserialize)]
+    #[serde(rename_all = "snake_case")]
+    enum TaskStatus {
+        Pending,
+        Running,
+        Complete,
+        Failed,
+        Cancelled,
+    }
+
+    impl TaskStatus {
+        const fn as_str(self) -> &'static str {
+            match self {
+                Self::Pending => "pending",
+                Self::Running => "running",
+                Self::Complete => "complete",
+                Self::Failed => "failed",
+                Self::Cancelled => "cancelled",
+            }
+        }
+
+        const fn icon(self) -> &'static str {
+            match self {
+                Self::Pending => "[ ]",
+                Self::Running => "[~]",
+                Self::Complete => "[x]",
+                Self::Failed => "[!]",
+                Self::Cancelled => "[-]",
+            }
+        }
+
+        fn all() -> &'static [Self] {
+            &[Self::Pending, Self::Running, Self::Complete, Self::Failed, Self::Cancelled]
+        }
+
+        const fn is_terminal(self) -> bool {
+            matches!(self, Self::Complete | Self::Failed | Self::Cancelled)
+        }
+    }
+
+    #[derive(Clone, Copy, Debug, PartialEq, Eq, Serialize, Deserialize)]
+    #[serde(rename_all = "snake_case")]
+    enum WorkflowState {
+        Init,
+        Running,
+        Paused,
+        Complete,
+        Failed,
+        Cancelled,
+    }
+
+    impl WorkflowState {
+        fn valid_transitions(self) -> Vec<Self> {
+            if self.is_terminal() {
+                return vec![];
+            }
+            match self {
+                Self::Init => vec![Self::Running, Self::Cancelled],
+                Self::Running => vec![Self::Paused, Self::Complete, Self::Failed, Self::Cancelled],
+                Self::Paused => vec![Self::Running, Self::Cancelled],
+                _ => vec![],
+            }
+        }
+
+        const fn is_terminal(self) -> bool {
+            matches!(self, Self::Complete | Self::Failed | Self::Cancelled)
+        }
+
+        fn all() -> &'static [Self] {
+            &[Self::Init, Self::Running, Self::Paused, Self::Complete, Self::Failed, Self::Cancelled]
+        }
+    }
+
+    #[derive(Clone, Debug, Serialize, Deserialize)]
+    struct TaskEntry {
+        id: String,
+        name: String,
+        status: TaskStatus,
+        connector: String,
