+    fn format_task_entry(task: &TaskEntry) -> String {
+        let icon = task.status.icon();
+        let dur = task
+            .duration_ms
+            .map(|ms| format!(" ({ms}ms)"))
+            .unwrap_or_default();
+        let err = task
+            .error
+            .as_ref()
+            .map(|e| format!(" -- {e}"))
+            .unwrap_or_default();
+        format!(
+            "{icon} {id}: {name} [{conn}.{op}]{dur}{err}",
+            id = task.id,
+            name = task.name,
+            conn = task.connector,
+            op = task.operation,
+        )
+    }
+
+    fn format_session_summary(s: &SessionSummary) -> String {
+        format!(
+            "Session {id} ({status})\n  Agent: {agent}\n  Goal: {goal}\n  Ops: {ops}\n  Duration: {dur}\n  Context: [{ctx}]",
+            id = s.session_id,
+            status = s.status,
+            agent = s.agent_name,
+            goal = s.goal,
+            ops = s.operations_completed,
+            dur = s.duration_human,
+            ctx = s.context_keys.join(", "),
+        )
+    }
+
+    fn format_pipeline_step(step: &PipelineStep) -> String {
+        let icon = step.status.icon();
+        let deps = if step.depends_on.is_empty() {
+            String::new()
+        } else {
+            format!(
+                " (after: {})",
+                step.depends_on
+                    .iter()
+                    .map(ToString::to_string)
+                    .collect::<Vec<_>>()
+                    .join(", ")
+            )
+        };
+        let mapping = step
+            .mapping
+            .as_ref()
+            .map(|m| format!(" [map: {m}]"))
+            .unwrap_or_default();
+        format!(
+            "{icon} Step {idx}: {conn}.{op}{mapping}{deps}",
+            idx = step.index,
+            conn = step.connector,
+            op = step.operation,
+        )
+    }
+
+    fn render_batch_progress_bar(progress: &BatchProgress, width: usize) -> String {
+        let fill = (progress.completed * width).checked_div(progress.total).unwrap_or(width);
+        let fail = (progress.failed * width).checked_div(progress.total).unwrap_or(0);
+        let empty = width.saturating_sub(fill + fail);
+        format!(
+            "[{done}{err}{space}] {pct:.1}% ({comp}/{total})",
+            done = "#".repeat(fill),
+            err = "!".repeat(fail),
+            space = ".".repeat(empty),
+            pct = progress.percent_complete,
+            comp = progress.completed,
+            total = progress.total,
+        )
+    }
