+                String::new()
+            } else {
+                format!(" <- [{}]", node.depends_on.join(", "))
+            };
+            lines.push(format!(
+                "{indent}{icon} {id}: {name}{deps}",
+                icon = node.status.icon(),
+                id = node.task_id,
+                name = node.name,
+            ));
+        }
